SELECT

FROM friend_requests fr
JOIN users requester ON requester.user_id = fr.requester_id
JOIN users addressee ON addressee.user_id = fr.addressee_id
WHERE fr.addressee_id = #{userId}

    AND fr.status = #{status}

ORDER BY CASE WHEN fr.status = 'PENDING' THEN 0 ELSE 1 END, fr.created_time DESC
LIMIT #{limit}

